import okhttp3.Interceptor
import okhttp3.OkHttpClient
import okhttp3.Response
import retrofit2.Retrofit
import retrofit2.converter.gson.GsonConverterFactory
import java.util.concurrent.TimeUnit

class NetworkModule {
    companion object {
        const val BASE_URL_DEV = "https://dev.api.example.com/"
        const val BASE_URL_STAGING = "https://staging.api.example.com/"
        const val BASE_URL_PRODUCTION = "https://api.example.com/"

        fun createClient(authToken: String, baseUrl: String): Retrofit {
            val okHttpClient = OkHttpClient.Builder()
                .addInterceptor(AuthInterceptor(authToken))
                .connectTimeout(30, TimeUnit.SECONDS)
                .readTimeout(30, TimeUnit.SECONDS)
                .build()

            return Retrofit.Builder()
                .baseUrl(baseUrl)
                .client(okHttpClient)
                .addConverterFactory(GsonConverterFactory.create())
                .build()
        }
    }

    private class AuthInterceptor(private val authToken: String) : Interceptor {
        override fun intercept(chain: Interceptor.Chain): Response {
            val originalRequest = chain.request()
            val newRequest = originalRequest.newBuilder()
                .header("Authorization", "Bearer $authToken")
                .build()
            return chain.proceed(newRequest)
        }
    }

    interface ApiService {
        @GET("users")
        fun fetchUserProfiles(): Call<List<UserProfile>>
    }

    data class UserProfile(
        val id: Int,
        val name: String,
        val email: String
    )
}

// Usage example
fun main() {
    val authToken = "your_auth_token_here"
    val environmentBaseUrl = NetworkModule.BASE_URL_PRODUCTION // Change based on the environment

    val retrofit = NetworkModule.createClient(authToken, environmentBaseUrl)
    val apiService = retrofit.create(NetworkModule.ApiService::class.java)

    // Make API call
    val response = apiService.fetchUserProfiles().execute()
    if (response.isSuccessful) {
        response.body()?.let { profiles ->
            for (profile in profiles) {
                println("ID: ${profile.id}, Name: ${profile.name}, Email: ${profile.email}")
            }
        }
    } else {
        println("Error: ${response.errorBody()?.string()}")
    }
}